"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["39720"],{99225(i){i.exports=JSON.parse('{"tag":{"label":"architecture","permalink":"/sysanalyst-kb.github.io/docs/tags/architecture","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":23,"items":[{"id":"architecture/adr","title":"ADR \u2014 Architecture Decision Records","description":"ADR \u2014 \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442, \u0444\u0438\u043A\u0441\u0438\u0440\u0443\u044E\u0449\u0438\u0439 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u043D\u043E\u0435 \u0440\u0435\u0448\u0435\u043D\u0438\u0435: \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442, \u0440\u0430\u0441\u0441\u043C\u043E\u0442\u0440\u0435\u043D\u043D\u044B\u0435 \u0432\u0430\u0440\u0438\u0430\u043D\u0442\u044B, \u0432\u044B\u0431\u0440\u0430\u043D\u043D\u044B\u0439 \u0432\u0430\u0440\u0438\u0430\u043D\u0442 \u0438 \u0435\u0433\u043E \u043F\u043E\u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u044F. \u041A\u0430\u0436\u0434\u043E\u0435 \u0440\u0435\u0448\u0435\u043D\u0438\u0435 \u2014 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u044B\u0439 \u0444\u0430\u0439\u043B \u0432 \u0440\u0435\u043F\u043E\u0437\u0438\u0442\u043E\u0440\u0438\u0438.","permalink":"/sysanalyst-kb.github.io/docs/architecture/adr"},{"id":"specialization/ai-agents-intro","title":"AI-\u0430\u0433\u0435\u043D\u0442\u044B \u2014 \u0432\u0432\u0435\u0434\u0435\u043D\u0438\u0435, \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u0438 \u043F\u0440\u0438\u043C\u0435\u043D\u0435\u043D\u0438\u0435","description":"AI-\u0430\u0433\u0435\u043D\u0442 \u2014 \u044D\u0442\u043E LLM, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E \u0433\u0435\u043D\u0435\u0440\u0438\u0440\u0443\u0435\u0442 \u0442\u0435\u043A\u0441\u0442, \u0430 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F: \u0432\u044B\u0437\u044B\u0432\u0430\u0435\u0442 API, \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0441 \u0444\u0430\u0439\u043B\u0430\u043C\u0438, \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0440\u0435\u0448\u0435\u043D\u0438\u044F. \u0412 \u043E\u0442\u043B\u0438\u0447\u0438\u0435 \u043E\u0442 RAG (\u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0442\u043E\u043B\u044C\u043A\u043E \u0438\u0449\u0435\u0442 \u0438 \u043E\u0442\u0432\u0435\u0447\u0430\u0435\u0442), \u0430\u0433\u0435\u043D\u0442 \u0441\u0430\u043C \u043F\u043B\u0430\u043D\u0438\u0440\u0443\u0435\u0442, \u043A\u0430\u043A\u0438\u0435 \u0448\u0430\u0433\u0438 \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0438 \u0432 \u043A\u0430\u043A\u043E\u043C \u043F\u043E\u0440\u044F\u0434\u043A\u0435. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0443 \u0432\u0430\u0436\u043D\u043E \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0443 \u0430\u0433\u0435\u043D\u0442\u043E\u0432, \u0447\u0442\u043E\u0431\u044B \u0444\u043E\u0440\u043C\u0443\u043B\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u043A \u0438\u0445 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u044E, \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u0438 \u0438 \u043D\u0430\u0434\u0435\u0436\u043D\u043E\u0441\u0442\u0438.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ai-agents-intro"},{"id":"specialization/ai-ml-architecture","title":"AI-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u2014 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 AI-\u0440\u0435\u0448\u0435\u043D\u0438\u0439 (MLOps, feature store)","description":"AI-\u0440\u0435\u0448\u0435\u043D\u0438\u0435 \u0432 \u043F\u0440\u043E\u0434\u0430\u043A\u0448\u043D\u0435 \u2014 \u044D\u0442\u043E \u043D\u0435 Jupyter-\u043D\u043E\u0443\u0442\u0431\u0443\u043A, \u0430 \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0438\u0437 \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u0438\u0445 \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u043E\u0432: \u043F\u0430\u0439\u043F\u043B\u0430\u0439\u043D \u0434\u0430\u043D\u043D\u044B\u0445, \u0445\u0440\u0430\u043D\u0438\u043B\u0438\u0449\u0435 \u043F\u0440\u0438\u0437\u043D\u0430\u043A\u043E\u0432, \u0441\u0435\u0440\u0432\u0438\u0441 \u0438\u043D\u0444\u0435\u0440\u0435\u043D\u0441\u0430, \u043C\u043E\u043D\u0438\u0442\u043E\u0440\u0438\u043D\u0433 \u0438 MLOps-\u0438\u043D\u0444\u0440\u0430\u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0430. AI-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0443 \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u043E\u0432, \u0438\u0445 \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u0438 \u043D\u0435\u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0435 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A\u0438.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ai-ml-architecture"},{"id":"specialization/telecom-bss-oss","title":"BSS/OSS \u2014 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 Telecom-\u0441\u0438\u0441\u0442\u0435\u043C","description":"\u0410\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 Telecom \u0434\u0435\u043B\u0438\u0442\u0441\u044F \u043D\u0430 BSS (Business Support Systems) \u0438 OSS (Operations Support Systems). BSS \u043E\u0442\u0432\u0435\u0447\u0430\u0435\u0442 \u0437\u0430 \u0430\u0431\u043E\u043D\u0435\u043D\u0442\u043E\u0432, \u0442\u0430\u0440\u0438\u0444\u044B, \u0431\u0438\u043B\u043B\u0438\u043D\u0433, \u0437\u0430\u043A\u0430\u0437\u044B. OSS \u2014 \u0437\u0430 \u043E\u0431\u043E\u0440\u0443\u0434\u043E\u0432\u0430\u043D\u0438\u0435 \u0441\u0435\u0442\u0438, \u0430\u043A\u0442\u0438\u0432\u0430\u0446\u0438\u044E \u0443\u0441\u043B\u0443\u0433 \u0438 \u043C\u043E\u043D\u0438\u0442\u043E\u0440\u0438\u043D\u0433. \u0421\u0442\u0430\u043D\u0434\u0430\u0440\u0442\u044B: TM Forum (eTOM, SID, TAM, Open API).","permalink":"/sysanalyst-kb.github.io/docs/specialization/telecom-bss-oss"},{"id":"modeling/c4-container","title":"C4 \u2014 Container diagram (\u0443\u0440\u043E\u0432\u0435\u043D\u044C 2)","description":"Container diagram \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442, \u0438\u0437 \u043A\u0430\u043A\u0438\u0445 \u0432\u044B\u0441\u043E\u043A\u043E\u0443\u0440\u043E\u0432\u043D\u0435\u0432\u044B\u0445 \u0431\u043B\u043E\u043A\u043E\u0432 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0441\u0438\u0441\u0442\u0435\u043C\u0430. \u041A\u043E\u043D\u0442\u0435\u0439\u043D\u0435\u0440 \u0432 C4 \u2014 \u044D\u0442\u043E \u043D\u0435 Docker, \u0430 \u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0435\u0434\u0438\u043D\u0438\u0446\u0430: \u0432\u0435\u0431-\u0441\u0435\u0440\u0432\u0435\u0440, \u0431\u0430\u0437\u0430 \u0434\u0430\u043D\u043D\u044B\u0445, \u043C\u043E\u0431\u0438\u043B\u044C\u043D\u043E\u0435 \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0435, \u043E\u0447\u0435\u0440\u0435\u0434\u044C \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0439.","permalink":"/sysanalyst-kb.github.io/docs/modeling/c4-container"},{"id":"modeling/c4-context","title":"C4 \u2014 Context diagram (\u0443\u0440\u043E\u0432\u0435\u043D\u044C 1)","description":"C4 \u2014 \u044D\u0442\u043E \u043D\u0435 \u043D\u043E\u0442\u0430\u0446\u0438\u044F, \u0430 \u0438\u0435\u0440\u0430\u0440\u0445\u0438\u044F \u043D\u043E\u0442\u0430\u0446\u0438\u0439. \u0427\u0435\u0442\u044B\u0440\u0435 \u0443\u0440\u043E\u0432\u043D\u044F \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u044E\u0442 \u0441\u0438\u0441\u0442\u0435\u043C\u0443 \u0441 \u0440\u0430\u0437\u043D\u043E\u0439 \u0441\u0442\u0435\u043F\u0435\u043D\u044C\u044E \u0434\u0435\u0442\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 Context \u0438 Container.","permalink":"/sysanalyst-kb.github.io/docs/modeling/c4-context"},{"id":"architecture/cqrs","title":"CQRS \u2014 Command Query Responsibility Segregation","description":"CQRS \u2014 \u043F\u0430\u0442\u0442\u0435\u0440\u043D, \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u044E\u0449\u0438\u0439 \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0438 \u0447\u0442\u0435\u043D\u0438\u044F (Query) \u0438 \u0437\u0430\u043F\u0438\u0441\u0438 (Command). \u0412 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u043E\u043D\u043D\u043E\u0439 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0435 \u043E\u0434\u043D\u0430 \u043C\u043E\u0434\u0435\u043B\u044C \u0434\u0430\u043D\u043D\u044B\u0445 \u0438 \u0434\u043B\u044F \u0447\u0442\u0435\u043D\u0438\u044F, \u0438 \u0434\u043B\u044F \u0437\u0430\u043F\u0438\u0441\u0438. CQRS \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u0435\u0442 \u0440\u0430\u0437\u043D\u044B\u0435 \u043C\u043E\u0434\u0435\u043B\u0438.","permalink":"/sysanalyst-kb.github.io/docs/architecture/cqrs"},{"id":"architecture/ddd-intro","title":"DDD \u2014 Domain-Driven Design (\u0432\u0432\u0435\u0434\u0435\u043D\u0438\u0435)","description":"Domain-Driven Design (DDD) \u2014 \u044D\u0442\u043E \u043F\u043E\u0434\u0445\u043E\u0434 \u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044E \u041F\u041E, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0441\u043B\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u0431\u0438\u0437\u043D\u0435\u0441-\u043B\u043E\u0433\u0438\u043A\u0438 \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u0432 \u0446\u0435\u043D\u0442\u0440\u0435 \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u044F. DDD \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u0435\u0442 \u043D\u0430\u0431\u043E\u0440 \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u0439 \u0438 \u043F\u0430\u0442\u0442\u0435\u0440\u043D\u043E\u0432 \u0434\u043B\u044F \u043C\u043E\u0434\u0435\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u043F\u0440\u0435\u0434\u043C\u0435\u0442\u043D\u043E\u0439 \u043E\u0431\u043B\u0430\u0441\u0442\u0438 (domain) \u0432 \u043A\u043E\u0434\u0435.","permalink":"/sysanalyst-kb.github.io/docs/architecture/ddd-intro"},{"id":"integration/event-driven-architecture","title":"Event-Driven Architecture (\u0432\u0432\u0435\u0434\u0435\u043D\u0438\u0435)","description":"Event-Driven Architecture (EDA) \u2014 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u043D\u044B\u0439 \u0441\u0442\u0438\u043B\u044C, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u044B \u043E\u0431\u0449\u0430\u044E\u0442\u0441\u044F \u0447\u0435\u0440\u0435\u0437 \u0441\u043E\u0431\u044B\u0442\u0438\u044F, \u0430 \u043D\u0435 \u0447\u0435\u0440\u0435\u0437 \u043F\u0440\u044F\u043C\u044B\u0435 \u0432\u044B\u0437\u043E\u0432\u044B. \u0415\u0441\u043B\u0438 \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u044B \u2014 \u043F\u0440\u043E \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u044C \u0434\u0435\u043F\u043B\u043E\u044F, \u0442\u043E EDA \u2014 \u043F\u0440\u043E \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u044C \u0432\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u0438 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435.","permalink":"/sysanalyst-kb.github.io/docs/integration/event-driven-architecture"},{"id":"architecture/eda-detailed","title":"Event-Driven Architecture (\u0434\u0435\u0442\u0430\u043B\u044C\u043D\u043E)","description":"\u0412\u044B \u0443\u0436\u0435 \u0437\u043D\u0430\u0435\u0442\u0435 \u043E\u0441\u043D\u043E\u0432\u044B EDA \u0438\u0437 \u0440\u0430\u0437\u0434\u0435\u043B\u0430 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438. \u0422\u0435\u043F\u0435\u0440\u044C \u0440\u0430\u0441\u0441\u043C\u043E\u0442\u0440\u0438\u043C \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u043D\u044B\u0435 \u0430\u0441\u043F\u0435\u043A\u0442\u044B: \u043A\u0430\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0441\u043E\u0431\u044B\u0442\u0438\u044F, \u043A\u0430\u043A \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043E\u0432\u044B\u0432\u0430\u0442\u044C \u043F\u043E\u0442\u043E\u043A\u0438 \u0438 \u043A\u0430\u043A EDA \u043C\u0435\u043D\u044F\u0435\u0442 \u0434\u0438\u0437\u0430\u0439\u043D \u0441\u0438\u0441\u0442\u0435\u043C\u044B.","permalink":"/sysanalyst-kb.github.io/docs/architecture/eda-detailed"},{"id":"architecture/hexagonal-architecture","title":"Hexagonal Architecture (Ports & Adapters)","description":"Hexagonal Architecture (\u0442\u0430\u043A\u0436\u0435 Ports & Adapters) \u2014 \u044D\u0442\u043E \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u043D\u044B\u0439 \u043F\u0430\u0442\u0442\u0435\u0440\u043D, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0438\u0437\u043E\u043B\u0438\u0440\u0443\u0435\u0442 \u0431\u0438\u0437\u043D\u0435\u0441-\u043B\u043E\u0433\u0438\u043A\u0443 \u043E\u0442 \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0441\u0438\u0441\u0442\u0435\u043C (\u0411\u0414, API, UI, message broker).","permalink":"/sysanalyst-kb.github.io/docs/architecture/hexagonal-architecture"},{"id":"architecture/saga-pattern","title":"Saga pattern \u2014 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0442\u0440\u0430\u043D\u0437\u0430\u043A\u0446\u0438\u044F\u043C\u0438","description":"Saga \u2014 \u044D\u0442\u043E \u043F\u0430\u0442\u0442\u0435\u0440\u043D \u0434\u043B\u044F \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u0451\u043D\u043D\u044B\u043C\u0438 \u0442\u0440\u0430\u043D\u0437\u0430\u043A\u0446\u0438\u044F\u043C\u0438 \u0432 \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u043D\u043E\u0439 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0435. \u041A\u043E\u0433\u0434\u0430 \u043E\u0434\u043D\u0430 \u0431\u0438\u0437\u043D\u0435\u0441-\u043E\u043F\u0435\u0440\u0430\u0446\u0438\u044F \u0437\u0430\u0442\u0440\u0430\u0433\u0438\u0432\u0430\u0435\u0442 \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0441\u0435\u0440\u0432\u0438\u0441\u043E\u0432, \u043E\u0431\u044B\u0447\u043D\u0430\u044F ACID-\u0442\u0440\u0430\u043D\u0437\u0430\u043A\u0446\u0438\u044F (\u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u0411\u0414) \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u0430. Saga \u043A\u043E\u043E\u0440\u0434\u0438\u043D\u0438\u0440\u0443\u0435\u0442 \u0448\u0430\u0433\u0438 \u0438 \u043A\u043E\u043C\u043F\u0435\u043D\u0441\u0430\u0446\u0438\u0438.","permalink":"/sysanalyst-kb.github.io/docs/architecture/saga-pattern"},{"id":"architecture/solid","title":"SOLID \u0434\u043B\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u043D\u043E\u0433\u043E \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430","description":"SOLID \u2014 \u043F\u044F\u0442\u044C \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u043E\u0432 \u043E\u0431\u044A\u0435\u043A\u0442\u043D\u043E-\u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F. \u0420\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0447\u0438\u043A\u0438 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442 \u0438\u0445 \u0434\u043B\u044F \u043D\u0430\u043F\u0438\u0441\u0430\u043D\u0438\u044F \u043A\u043E\u0434\u0430. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442 \u0438\u0445 \u0434\u043B\u044F \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u044B: \u043A\u0430\u043A \u0434\u0435\u043B\u0438\u0442\u044C \u043D\u0430 \u043C\u043E\u0434\u0443\u043B\u0438, \u043A\u0430\u043A \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0442\u044C \u0438\u043D\u0442\u0435\u0440\u0444\u0435\u0439\u0441\u044B, \u043A\u0430\u043A \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0442\u044C \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u044F\u043C\u0438.","permalink":"/sysanalyst-kb.github.io/docs/architecture/solid"},{"id":"architecture/strangler-fig","title":"Strangler Fig \u2014 \u043C\u0438\u0433\u0440\u0430\u0446\u0438\u044F legacy","description":"Strangler Fig (\u0438\u043B\u0438 Strangler Pattern) \u2014 \u044D\u0442\u043E \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u044F \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E\u0439 \u0437\u0430\u043C\u0435\u043D\u044B legacy-\u0441\u0438\u0441\u0442\u0435\u043C\u044B \u043D\u0430 \u043D\u043E\u0432\u0443\u044E \u0431\u0435\u0437 \u043F\u0440\u043E\u0441\u0442\u043E\u0435\u0432 \u0438 big-bang \u043C\u0438\u0433\u0440\u0430\u0446\u0438\u0438.","permalink":"/sysanalyst-kb.github.io/docs/architecture/strangler-fig"},{"id":"modeling/component-diagram","title":"UML \u2014 Component diagram","description":"Component diagram \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442, \u043A\u0430\u043A \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u044B \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u0441\u0432\u044F\u0437\u0430\u043D\u044B \u0434\u0440\u0443\u0433 \u0441 \u0434\u0440\u0443\u0433\u043E\u043C \u0447\u0435\u0440\u0435\u0437 \u0438\u043D\u0442\u0435\u0440\u0444\u0435\u0439\u0441\u044B. \u042D\u0442\u043E \u043C\u043E\u0441\u0442 \u043C\u0435\u0436\u0434\u0443 \u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u043C\u043E\u0434\u0435\u043B\u044C\u044E (\u043A\u043B\u0430\u0441\u0441\u044B) \u0438 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0439 (\u0434\u0435\u043F\u043B\u043E\u0439).","permalink":"/sysanalyst-kb.github.io/docs/modeling/component-diagram"},{"id":"specialization/govtech-gis-architecture","title":"\u0410\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u0413\u0418\u0421 \u2014 \u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B","description":"\u0413\u0418\u0421 (\u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430) \u2014 \u0418\u0421 \u0434\u043B\u044F \u043E\u043A\u0430\u0437\u0430\u043D\u0438\u044F \u0433\u043E\u0441\u0443\u0441\u043B\u0443\u0433, \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F \u0433\u043E\u0441\u0444\u0443\u043D\u043A\u0446\u0438\u0439 \u0438\u043B\u0438 \u043C\u0435\u0436\u0432\u0435\u0434\u043E\u043C\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F. \u0410\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u0413\u0418\u0421 \u0432\u043A\u043B\u044E\u0447\u0430\u0435\u0442 \u0415\u041F\u0413\u0423 (110M+ \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u0439), \u0413\u0418\u0421 \u0413\u041C\u041F (500M+ \u043F\u043B\u0430\u0442\u0435\u0436\u0435\u0439/\u0433\u043E\u0434), \u0415\u0413\u0418\u0421\u0421\u041E (100M+ \u0437\u0430\u043F\u0438\u0441\u0435\u0439).","permalink":"/sysanalyst-kb.github.io/docs/specialization/govtech-gis-architecture"},{"id":"specialization/gamedev-architecture","title":"\u0410\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u0438\u0433\u0440\u043E\u0432\u044B\u0445 \u043F\u0440\u043E\u0435\u043A\u0442\u043E\u0432","description":"\u0418\u0433\u0440\u043E\u0432\u0430\u044F \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0438\u0430\u043B\u044C\u043D\u043E \u043E\u0442\u043B\u0438\u0447\u0430\u0435\u0442\u0441\u044F \u043E\u0442 Enterprise. \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u0438: authoritative server (\u0441\u0435\u0440\u0432\u0435\u0440 \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0432\u0441\u0435 \u0440\u0435\u0448\u0435\u043D\u0438\u044F), client-side prediction (\u043A\u043B\u0438\u0435\u043D\u0442 \u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442, \u0447\u0442\u043E\u0431\u044B \u0441\u043A\u0440\u044B\u0442\u044C \u043B\u0430\u0433), UDP \u0432\u043C\u0435\u0441\u0442\u043E TCP (\u0441\u043A\u043E\u0440\u043E\u0441\u0442\u044C \u0432\u0430\u0436\u043D\u0435\u0435 \u043D\u0430\u0434\u0451\u0436\u043D\u043E\u0441\u0442\u0438), Entity-Component pattern, state synchronization \u0438 rollback netcode \u0434\u043B\u044F fighting/RTS \u0438\u0433\u0440. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u044D\u0442\u0438 \u043F\u0430\u0442\u0442\u0435\u0440\u043D\u044B, \u0447\u0442\u043E\u0431\u044B \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C API \u0438\u0433\u0440\u043E\u0432\u043E\u0433\u043E \u0431\u044D\u043A\u0435\u043D\u0434\u0430 \u0438 \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438.","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-architecture"},{"id":"basics/client-server-basics","title":"\u041A\u043B\u0438\u0435\u043D\u0442-\u0441\u0435\u0440\u0432\u0435\u0440\u043D\u0430\u044F \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430","description":"\u041A\u043B\u0438\u0435\u043D\u0442-\u0441\u0435\u0440\u0432\u0435\u0440 \u2014 \u044D\u0442\u043E \u043A\u0430\u043A \u0440\u0435\u0441\u0442\u043E\u0440\u0430\u043D: \u043A\u043B\u0438\u0435\u043D\u0442 (\u0432\u044B) \u0437\u0430\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0435 \u0447\u0435\u0440\u0435\u0437 \u043E\u0444\u0438\u0446\u0438\u0430\u043D\u0442\u0430 (\u0438\u043D\u0442\u0435\u0440\u043D\u0435\u0442), \u0430 \u043A\u0443\u0445\u043D\u044F (\u0441\u0435\u0440\u0432\u0435\u0440) \u0433\u043E\u0442\u043E\u0432\u0438\u0442 \u0438 \u043E\u0442\u0434\u0430\u0451\u0442 \u0431\u043B\u044E\u0434\u043E (\u0434\u0430\u043D\u043D\u044B\u0435).","permalink":"/sysanalyst-kb.github.io/docs/basics/client-server-basics"},{"id":"architecture/microservices-patterns","title":"\u041C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u044B \u2014 \u0431\u0430\u0437\u043E\u0432\u044B\u0435 \u043F\u0430\u0442\u0442\u0435\u0440\u043D\u044B","description":"\u041F\u0435\u0440\u0435\u0445\u043E\u0434 \u043D\u0430 \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u044B \u2014 \u044D\u0442\u043E \u043D\u0435 \u043F\u0440\u043E \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u044E, \u0430 \u043F\u0440\u043E \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u044E. \u041A\u0430\u0436\u0434\u044B\u0439 \u043F\u0430\u0442\u0442\u0435\u0440\u043D \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u043D\u043E\u0439 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u044B \u0440\u0435\u0448\u0430\u0435\u0442 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u0443\u044E \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u0443, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 \u043F\u0440\u0438 \u0434\u0435\u043B\u0435\u043D\u0438\u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u043D\u0430 \u0447\u0430\u0441\u0442\u0438.","permalink":"/sysanalyst-kb.github.io/docs/architecture/microservices-patterns"},{"id":"architecture/monolith-vs-microservices","title":"\u041C\u043E\u043D\u043E\u043B\u0438\u0442 vs \u041C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u044B","description":"\u0421\u043F\u043E\u0440 \xab\u043C\u043E\u043D\u043E\u043B\u0438\u0442 \u0438\u043B\u0438 \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u044B\xbb \u0434\u0430\u0432\u043D\u043E \u043F\u043E\u0442\u0435\u0440\u044F\u043B \u0441\u043C\u044B\u0441\u043B. \u042D\u0442\u043E \u043D\u0435 \u0432\u043E\u043F\u0440\u043E\u0441 \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u0438, \u0430 \u0432\u043E\u043F\u0440\u043E\u0441 \u043A\u043E\u043C\u043F\u0440\u043E\u043C\u0438\u0441\u0441\u0430. \u041E\u0431\u0430 \u043F\u043E\u0434\u0445\u043E\u0434\u0430 \u0438\u043C\u0435\u044E\u0442 \u0446\u0435\u043D\u0443, \u0438 \u0432\u044B\u0431\u043E\u0440 \u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u043E\u0442 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0430: \u0441\u0442\u0430\u0434\u0438\u0438 \u043F\u0440\u043E\u0435\u043A\u0442\u0430, \u0440\u0430\u0437\u043C\u0435\u0440\u0430 \u043A\u043E\u043C\u0430\u043D\u0434\u044B, \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u0439 \u043A \u043C\u0430\u0441\u0448\u0442\u0430\u0431\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044E.","permalink":"/sysanalyst-kb.github.io/docs/architecture/monolith-vs-microservices"},{"id":"specialization/solution-architect-path","title":"\u041F\u0443\u0442\u044C Solution-\u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u043E\u0440\u0430","description":"Solution Architect (SArch) \u2014 \u044D\u0442\u043E \u0440\u043E\u043B\u044C, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0441\u043E\u0435\u0434\u0438\u043D\u044F\u0435\u0442 \u0431\u0438\u0437\u043D\u0435\u0441 \u0438 \u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044E. Solution Architect \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0440\u0435\u0448\u0435\u043D\u0438\u0435 \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B: \u0432\u044B\u0431\u043E\u0440 \u0442\u0435\u0445\u043D\u043E\u043B\u043E\u0433\u0438\u0439, \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438, \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u043D\u044B\u0435 \u0441\u0442\u0438\u043B\u0438, \u043E\u0446\u0435\u043D\u043A\u0430 \u0441\u0442\u043E\u0438\u043C\u043E\u0441\u0442\u0438.","permalink":"/sysanalyst-kb.github.io/docs/specialization/solution-architect-path"},{"id":"architecture/layered-architecture","title":"\u0421\u043B\u043E\u0438\u0441\u0442\u0430\u044F \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 (layered)","description":"\u0421\u043B\u043E\u0438\u0441\u0442\u0430\u044F \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u2014 \u0441\u0430\u043C\u044B\u0439 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0451\u043D\u043D\u044B\u0439 \u0441\u043F\u043E\u0441\u043E\u0431 \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u0438 \u043A\u043E\u0434\u0430. \u0418\u0434\u0435\u044F \u043F\u0440\u043E\u0441\u0442\u0430: \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0434\u0435\u043B\u0438\u0442\u0441\u044F \u043D\u0430 \u0433\u043E\u0440\u0438\u0437\u043E\u043D\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u0443\u0440\u043E\u0432\u043D\u0438, \u043A\u0430\u0436\u0434\u044B\u0439 \u043E\u0442\u0432\u0435\u0447\u0430\u0435\u0442 \u0437\u0430 \u0441\u0432\u043E\u044E \u0437\u043E\u043D\u0443 \u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438. \u0412\u0435\u0440\u0445\u043D\u0438\u0439 \u0441\u043B\u043E\u0439 \u043C\u043E\u0436\u0435\u0442 \u043E\u0431\u0440\u0430\u0449\u0430\u0442\u044C\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u043A \u0441\u043E\u0441\u0435\u0434\u043D\u0435\u043C\u0443 \u043D\u0438\u0436\u043D\u0435\u043C\u0443 \u2014 \u044D\u0442\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u043E \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0441\u0442\u0440\u043E\u0433\u043E\u0439 \u0438\u0435\u0440\u0430\u0440\u0445\u0438\u0435\u0439.","permalink":"/sysanalyst-kb.github.io/docs/architecture/layered-architecture"},{"id":"architecture/what-is-architecture","title":"\u0427\u0442\u043E \u0442\u0430\u043A\u043E\u0435 \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u041F\u041E","description":"\u0410\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u2014 \u044D\u0442\u043E \u0440\u0435\u0448\u0435\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0441\u043B\u043E\u0436\u043D\u043E \u0438\u0437\u043C\u0435\u043D\u0438\u0442\u044C \u043F\u043E\u0441\u043B\u0435 \u0442\u043E\u0433\u043E, \u043A\u0430\u043A \u043E\u043D\u0438 \u043F\u0440\u0438\u043D\u044F\u0442\u044B. \u0415\u0441\u043B\u0438 \u043D\u0435\u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E\u0435 \u0438\u043C\u044F \u0444\u0443\u043D\u043A\u0446\u0438\u0438 \u043C\u043E\u0436\u043D\u043E \u0438\u0441\u043F\u0440\u0430\u0432\u0438\u0442\u044C \u0437\u0430 \u043C\u0438\u043D\u0443\u0442\u0443, \u0442\u043E \u043D\u0435\u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u044B\u0439 \u0432\u044B\u0431\u043E\u0440 \u043C\u0435\u0436\u0434\u0443 \u043C\u043E\u043D\u043E\u043B\u0438\u0442\u043E\u043C \u0438 \u043C\u0438\u043A\u0440\u043E\u0441\u0435\u0440\u0432\u0438\u0441\u0430\u043C\u0438 \u0431\u0443\u0434\u0435\u0442 \u0430\u0443\u043A\u0430\u0442\u044C\u0441\u044F \u0433\u043E\u0434\u0430\u043C\u0438.","permalink":"/sysanalyst-kb.github.io/docs/architecture/what-is-architecture"}],"unlisted":false}}')}}]);